import sqlite3
import re
from flask import Flask, render_template, request, redirect, url_for, session, g
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(Config.DATABASE)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def sanitize_input(data):
    # Simple WAF: strips keywords once (vulnerable to nested keywords)
    keywords = ['SELECT', 'UNION', 'WHERE', 'FROM', 'AND', 'OR', 'LIKE', 'GROUP', 'BY', 'HAVING']
    for word in keywords:
        pattern = re.compile(re.escape(word), re.IGNORECASE)
        data = pattern.sub('', data)
    return data

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user_id'] = user['id']
            session['username'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session: return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/profile', methods=['GET'])
def profile():
    if 'user_id' not in session: return redirect(url_for('login'))
    db = get_db()
    user = db.execute('SELECT * FROM users WHERE id = ?', (session['user_id'],)).fetchone()
    return render_template('profile.html', user=user)

@app.route('/profile/update', methods=['POST'])
def update_profile():
    if 'user_id' not in session: return redirect(url_for('login'))
    new_org = request.form.get('org_name', 'Obsidian')
    # The developer implemented a WAF here
    sanitized_org = sanitize_input(new_org)

    db = get_db()
    db.execute('UPDATE users SET org_name = ? WHERE id = ?', (sanitized_org, session['user_id']))
    db.commit()
    return redirect(url_for('profile', msg="Profile updated successfully"))

@app.route('/manifests')
def manifests():
    if 'user_id' not in session: return redirect(url_for('login'))
    db = get_db()
    user = db.execute('SELECT * FROM users WHERE id = ?', (session['user_id'],)).fetchone()

    # VULNERABILITY: Second-order SQL Injection
    # The org_name was sanitized on entry, but is used unsafely here.
    # A player can bypass the 'sanitize_input' on the profile page using nested keywords.
    org = user['org_name']
    try:
        query = f"SELECT * FROM cargo WHERE owner_org = '{org}'"
        results = db.execute(query).fetchall()
    except Exception as e:
        return render_template('manifests.html', error=f"System Error: Query Failed", debug_info=str(e))

    return render_template('manifests.html', manifests=results)

@app.route('/vessels')
def vessels():
    db = get_db()
    vessels = db.execute('SELECT * FROM vessels').fetchall()
    return render_template('vessels.html', vessels=vessels)

@app.route('/api/v1/status')
def status():
    return {"status": "operational", "version": "2.4.1", "db_engine": "sqlite3"}

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)

